/// <summary>
/// Event handler for the form <c>InventValueProcess</c> specific to the ETGSPAIN model.
/// </summary>
internal final class ETGSPAINInventValueProcessEventHandler
{    
}

Method.Source:
/// <summary>
/// Extension of the <c>updateReportLineProfitLoss</c> method.
/// </summary>
/// <remarks>
/// This method is used to populate additional fields in the <c>InventValueReportTmpLine</c> table
/// for the ETGSPAIN model.
/// </remarks>
/// <param name="sender">The <c>xFormRun</c> instance.</param>
/// <param name="e">The <c>FormEventArgs</c> instance.</param>
[FormEventHandler(formStr(InventValueProcess), FormEventType::Initialized)]
public static void InventValueProcess_OnInitialized(xFormRun _sender, FormEventArgs _e)
{
    InventValueExecutionHistory     inventValueExecutionHistory;
    InventValueReportTmpLine        inventValueReportTmpLine;

    if (_sender.args().dataset() == tableNum(InventValueExecutionHistory))
    {
        inventValueExecutionHistory = _sender.args().record() as InventValueExecutionHistory;

        ttsbegin;
        while select forupdate inventValueReportTmpLine
            where inventValueReportTmpLine.TransactionId == inventValueExecutionHistory.TransactionId
                && ((inventValueReportTmpLine.InventLocationId && !inventValueReportTmpLine.ETGSPAINInventLocationAdressCity)
                    || (inventValueReportTmpLine.InventBatchId && !inventValueReportTmpLine.ETGSPAINPurchOperationName))

        {
            inventValueReportTmpLine.ETGSPAINPreWriteInventValueReportTmpLine();
            inventValueReportTmpLine.update();
        }
        ttscommit;
    }
}
